import { useEffect, useState } from "react";
import axios from "../api/axios";

export default function MyBookings() {
  const [bookings, setBookings] = useState([]);

  const load = () => {
    axios.get("/bookings/my").then(res => setBookings(res.data));
  };

  useEffect(load, []);

  const cancel = async (id) => {
    await axios.delete(`/bookings/${id}`);
    load();
  };

  return (
    <div className="container">
      <h2>My Bookings</h2>
      {bookings.length === 0 ? (
        <p style={{ marginTop: "20px", color: "var(--text-secondary)" }}>You have no bookings yet.</p>
      ) : (
        <>
          {/* ACTIVE BOOKINGS SECTION */}
          <h3 style={{ marginTop: '20px', marginBottom: '15px', color: '#28a745' }}>Active Reservations 🟢</h3>
          <div className="grid">
            {bookings.filter(b => b.status === "Active").length === 0 ? <p style={{ color: '#666' }}>No active reservations.</p> :
              bookings.filter(b => b.status === "Active").map(b => (
                <div className="card" key={b._id} style={{ borderLeft: '5px solid #28a745' }}>
                  <h3>Booking #{b._id.slice(-4)}</h3>
                  <p>📍 Slot: <strong>{b.slotId?.slotNumber || "Unknown Slot"}</strong></p>
                  <p>📅 Date: {new Date(b.startTime).toLocaleDateString()}</p>
                  <p>🕒 Time: {new Date(b.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(b.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                  <button
                    onClick={() => cancel(b._id)}
                    style={{ background: "var(--status-danger)", marginTop: '10px' }}
                    className="btn-primary"
                  >
                    Cancel Reservation
                  </button>
                </div>
              ))
            }
          </div>

          {/* HISTORY SECTION */}
          <h3 style={{ marginTop: '40px', marginBottom: '15px', color: '#666', borderTop: '1px solid #ccc', paddingTop: '20px' }}>Booking History 📜</h3>
          <div className="grid">
            {bookings.filter(b => b.status !== "Active").length === 0 ? <p style={{ color: '#666' }}>No past history.</p> :
              bookings.filter(b => b.status !== "Active").map(b => (
                <div className="card" key={b._id} style={{ opacity: 0.7, background: '#f9f9f9', borderLeft: b.status === 'Completed' ? '5px solid #6c757d' : '5px solid #dc3545' }}>
                  <h3 style={{ color: '#666' }}>Booking #{b._id.slice(-4)} <span style={{ fontSize: '0.6em', background: b.status === 'Completed' ? '#28a745' : '#dc3545', color: 'white', padding: '2px 6px', borderRadius: '4px', verticalAlign: 'middle' }}>{b.status}</span></h3>
                  <p>📍 Slot: <strong>{b.slotId?.slotNumber || "Unknown Slot"}</strong></p>
                  <p>📅 Date: {new Date(b.startTime).toLocaleDateString()}</p>
                  <p>🕒 Time: {new Date(b.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} - {new Date(b.endTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                </div>
              ))
            }
          </div>
        </>
      )}
    </div>
  );
}
